package com.panini.back.config; import com.panini.back.service.JwtService; import jakarta.servlet.*; import jakarta.servlet.http.*; import org.springframework.beans.factory.annotation.Value; import org.springframework.context.annotation.*; import org.springframework.http.HttpHeaders; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.config.Customizer; import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.config.http.SessionCreationPolicy; import org.springframework.security.core.authority.SimpleGrantedAuthority; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.web.SecurityFilterChain; import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter; import org.springframework.security.web.context.SecurityContextHolderFilter; import org.springframework.web.cors.*; import org.springframework.web.filter.OncePerRequestFilter; import java.io.IOException; import java.util.List; @Configuration @EnableMethodSecurity public class SecurityConfig { @Bean PasswordEncoder passwordEncoder(){ return new BCryptPasswordEncoder(); } @Bean CorsConfigurationSource corsConfigurationSource(@Value("${app.frontend.origin}") String origin){ CorsConfiguration c=new CorsConfiguration(); c.setAllowedOrigins(List.of(origin)); c.setAllowedMethods(List.of("GET","POST","PUT","DELETE","OPTIONS")); c.setAllowedHeaders(List.of("*")); c.setAllowCredentials(true); UrlBasedCorsConfigurationSource s=new UrlBasedCorsConfigurationSource(); s.registerCorsConfiguration("/**", c); return s; } @Bean SecurityFilterChain chain(HttpSecurity http, JwtService jwt) throws Exception { return http.csrf(csrf->csrf.disable()).cors(Customizer.withDefaults()).sessionManagement(sm->sm.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).authorizeHttpRequests(auth->auth.requestMatchers("/api/auth/**","/error").permitAll().anyRequest().authenticated()).addFilterBefore(new OncePerRequestFilter(){ @Override protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res, FilterChain chain) throws ServletException, IOException { String h=req.getHeader(HttpHeaders.AUTHORIZATION); if(h!=null && h.startsWith("Bearer ")){ try{ String u=jwt.extractUsername(h.substring(7)); SecurityContextHolder.getContext().setAuthentication(new UsernamePasswordAuthenticationToken(u,null,List.of(new SimpleGrantedAuthority("ROLE_USER")))); }catch(Exception ignored){} } chain.doFilter(req,res); } }, UsernamePasswordAuthenticationFilter.class).build(); } }
